import React, { useCallback, useEffect, useRef, useState, Suspense } from 'react'
import PropTypes from 'prop-types'
import { baseLocales, i18n } from '@fs/zion-locale'
import { trackEvent } from '@fs/zion-analytics'
import { getLanguage, stdLog, LOG_LEVEL, useProposedPlaces } from '@fs/zion-standards'
import { useFeatureFlag } from '@fs/zion-flags'
import { suggestNewProvisionalPlaceNEXT } from './lib/provisionalPlaceService'

const SelectPlaceType = React.lazy(() => import('./components/SelectPlaceType/SelectPlaceType'))
const NarrowSearchFormNEXT = React.lazy(() => import('./components/NarrowSearchForm/NarrowSearchFormNEXT'))
const NewSearchSelectOrCreatePlaceContent = React.lazy(
  () => import('./components/NewSearchSelectOrCreatePlaceContent/NewSearchSelectOrCreatePlaceContent')
)
const NewProvisionalPlaceForm = React.lazy(() => import('./components/NewProvisionalPlaceForm/NewProvisionalPlaceForm'))
const PlaceRequestSubmittedContent = React.lazy(
  () => import('./components/PlaceRequestSubmittedContent/PlaceRequestSubmittedContent')
)

const DIALOG_STATES = {
  selectPlaceType: 'selectPlaceType',
  narrowSearch: 'narrowSearch',
  newSearchSelectOrCreatePlace: 'newSearchSelectOrCreatePlace',
  newPlaceForm: 'newPlaceForm',
  narrowSearchAgain: 'narrowSearchAgain',
  submitted: 'submitted',
  proposed: 'proposed',
}

function getDialogHeaderTitle(dialogState) {
  switch (dialogState) {
    case DIALOG_STATES.selectPlaceType:
      return i18n.t('provisional-place.select-place-type.heading', 'Select a Category')
    case DIALOG_STATES.narrowSearch:
      return i18n.t('provisional-place.narrow-search.heading', 'Enter a Place Name')
    case DIALOG_STATES.newSearchSelectOrCreatePlace:
      return i18n.t('provisional-place.search-results.heading', 'Search Results')
    case DIALOG_STATES.narrowSearchAgain:
      return i18n.t('provisional-place.narrow-search.heading', 'Enter a Place Name')
    case DIALOG_STATES.newPlaceForm:
      return i18n.t('provisional-place.new-place-form.heading', 'Add Details')
    case DIALOG_STATES.proposed:
      return i18n.t('provisional-place.request-submitted.heading', 'Place Request Submitted')
    default:
      return i18n.t('provisional-place.suggest-place.heading', 'Suggest a New place')
  }
}

function HeaderLabelInfoText({ label = '', textValue = '' }) {
  return (
    <span style={{ display: 'block' }}>
      {label}: <span style={{ fontWeight: 'bold' }}>{textValue}</span>
    </span>
  )
}

function getDialogSubheadingText(dialogState, placeType, provisionalPlaceFormValues) {
  switch (dialogState) {
    case DIALOG_STATES.selectPlaceType:
      return null
    case DIALOG_STATES.narrowSearchAgain:
    case DIALOG_STATES.narrowSearch: {
      return (
        <HeaderLabelInfoText
          label={i18n.t('provisional-place.place-type.label', 'Place Type')}
          textValue={placeType?.primaryText}
        />
      )
    }
    case DIALOG_STATES.newSearchSelectOrCreatePlace:
    case DIALOG_STATES.newPlaceForm: {
      return (
        <>
          <HeaderLabelInfoText
            label={i18n.t('provisional-place.place-type.label', 'Place Type')}
            textValue={placeType?.primaryText}
          />

          <HeaderLabelInfoText
            label={i18n.t('provisional-place.place-name.label', 'Place Name')}
            textValue={provisionalPlaceFormValues?.placeName}
          />
          <HeaderLabelInfoText
            label={i18n.t('provisional-place.parent-place.label', 'Parent Place')}
            textValue={provisionalPlaceFormValues?.parentPlace?.selectedItem?.primaryText}
          />
          <HeaderLabelInfoText
            label={i18n.t('provisional-place.language-of-place.label', 'Language of the Place')}
            textValue={provisionalPlaceFormValues?.placeLang?.selectedItem?.primaryText}
          />
        </>
      )
    }

    default:
      return null
  }
}

export default function ProvisionalPlaceNEXT({
  placeName = '',
  overlay,
  onSubmit,
  onCancel,
  onSelectExistingPlace,
  isProposed = false,
}) {
  const logLevelFeature = useFeatureFlag('standards_log_level')
  const logLevelFlag = Number(logLevelFeature?.config?.logLevel ?? LOG_LEVEL.OFF)
  const [placeType, setPlaceType] = useState()
  const [dialogState, setDialogState] = useState(DIALOG_STATES.selectPlaceType)
  const [narrowSearchFormValues, setNarrowSearchFormValues] = useState({
    placeName,
    placeLang: getLanguage(baseLocales.includes(i18n.language) ? i18n.language : 'en'),
  })
  const [provisionalPlaceFormValues, setProvisionalPlaceFormValues] = useState({})
  const [error, setError] = useState(null)
  const { proposedSuggestions, addProposedPlaceRep } = useProposedPlaces()
  const headerTitle = getDialogHeaderTitle(dialogState)
  const subHeadingText = getDialogSubheadingText(dialogState, placeType, provisionalPlaceFormValues)
  const language = i18n.language
  const resetFormState = useCallback(() => {
    setDialogState(DIALOG_STATES.selectPlaceType)
    setError(null)
    setPlaceType(null)
    setNarrowSearchFormValues({ placeName, placeLang: getLanguage(baseLocales.includes(language) ? language : 'en') })
  }, [placeName, language])

  useEffect(() => {
    setNarrowSearchFormValues({
      placeName,
      placeLang: getLanguage(baseLocales.includes(i18n.language) ? i18n.language : 'en'),
    })
  }, [placeName])

  const wasOpenRef = useRef(overlay.isOpen)

  // Reset form state only after an actual open→closed transition completes
  useEffect(() => {
    if (overlay.isOpen) {
      wasOpenRef.current = true
      return
    }
    if (
      wasOpenRef.current &&
      !overlay.transitioning &&
      dialogState !== DIALOG_STATES.submitted &&
      dialogState !== DIALOG_STATES.proposed
    ) {
      wasOpenRef.current = false
      const logString = `message=User Exited PPF ppfStatus=${dialogState} ppfFormValues=${JSON.stringify(
        provisionalPlaceFormValues
      )}`
      stdLog({ msg: logString, component: 'PlaceSuggest', logLevel: LOG_LEVEL.WARN, logLevelFlag })
      resetFormState()
    }
  }, [overlay.isOpen, overlay.transitioning, dialogState, provisionalPlaceFormValues, resetFormState, logLevelFlag])

  const handleOnNext = ({ values }) => {
    trackEvent({ event_name: 'placeSuggest-nextButtonClicked' })
    switch (dialogState) {
      case DIALOG_STATES.selectPlaceType:
        setDialogState(DIALOG_STATES.narrowSearch)
        break
      case DIALOG_STATES.narrowSearch:
      case DIALOG_STATES.narrowSearchAgain:
        setProvisionalPlaceFormValues(values)
        setDialogState(DIALOG_STATES.newSearchSelectOrCreatePlace)
        break
      case DIALOG_STATES.newSearchSelectOrCreatePlace:
        setError(null)
        setDialogState(DIALOG_STATES.newPlaceForm)
        break
      case DIALOG_STATES.newPlaceForm:
        setProvisionalPlaceFormValues(values)
        setDialogState(DIALOG_STATES.proposed)
        break
      default:
        throw Error('Invalid Dialog State')
    }
  }

  const handleOnBack = () => {
    switch (dialogState) {
      case DIALOG_STATES.newPlaceForm:
      case DIALOG_STATES.submitted:
        setError(null)
        setDialogState(DIALOG_STATES.newSearchSelectOrCreatePlace)
        break
      case DIALOG_STATES.newSearchSelectOrCreatePlace:
        setDialogState(DIALOG_STATES.narrowSearchAgain)
        break
      case DIALOG_STATES.narrowSearch:
      case DIALOG_STATES.narrowSearchAgain:
        setDialogState(DIALOG_STATES.selectPlaceType)
        break
      default:
        throw Error('Invalid Dialog State')
    }
  }

  async function createProvisionalPlace(values) {
    let resp = null
    try {
      resp = await suggestNewProvisionalPlaceNEXT({ values, placeType, isProposed, logLevelFlag })
      if (isProposed && resp?.data?.placeRep) {
        await addProposedPlaceRep(resp.data.placeRep)
      }
      onSubmit(values, resp)
      setDialogState(DIALOG_STATES.selectPlaceType)
      resetFormState()
    } catch (err) {
      setError(err)
      setDialogState(DIALOG_STATES.newPlaceForm)
    }
    return resp
  }

  const handleOnSubmit = ({ values }) => {
    if (
      dialogState !== DIALOG_STATES.newPlaceForm &&
      dialogState !== DIALOG_STATES.submitted &&
      dialogState !== DIALOG_STATES.proposed
    ) {
      throw Error('Invalid Dialog State')
    }
    if (dialogState === DIALOG_STATES.newPlaceForm || dialogState === DIALOG_STATES.proposed) {
      setDialogState(DIALOG_STATES.submitted)
      createProvisionalPlace({ ...values, ...provisionalPlaceFormValues })
    }
  }

  const handleOnCancel = () => {
    trackEvent({ event_name: 'placeSuggest-cancelButtonClicked' })
    resetFormState()
    if (onCancel) {
      onCancel()
    }
  }

  const onSearchAgain = () => {
    setDialogState(DIALOG_STATES.narrowSearchAgain)
  }

  return (
    <Suspense fallback={null}>
      {dialogState === DIALOG_STATES.selectPlaceType && (
        <SelectPlaceType
          title={headerTitle}
          subtitle={subHeadingText}
          overlay={overlay}
          selected={placeType}
          onCancel={handleOnCancel}
          onNext={handleOnNext}
          onChange={setPlaceType}
        />
      )}
      {dialogState === DIALOG_STATES.narrowSearch && (
        <NarrowSearchFormNEXT
          title={headerTitle}
          subtitle={subHeadingText}
          overlay={overlay}
          placeType={placeType}
          narrowSearchFormValues={narrowSearchFormValues}
          onBack={handleOnBack}
          onNext={handleOnNext}
          onChange={setNarrowSearchFormValues}
        />
      )}
      {dialogState === DIALOG_STATES.narrowSearchAgain && (
        <NarrowSearchFormNEXT
          title={headerTitle}
          subtitle={subHeadingText}
          overlay={overlay}
          placeType={placeType}
          narrowSearchFormValues={narrowSearchFormValues}
          placeName={placeName}
          onBack={handleOnBack}
          onNext={handleOnNext}
          onChange={setNarrowSearchFormValues}
          noWarning
        />
      )}
      {dialogState === DIALOG_STATES.newSearchSelectOrCreatePlace && (
        <NewSearchSelectOrCreatePlaceContent
          title={headerTitle}
          subtitle={subHeadingText}
          overlay={overlay}
          provisionalPlaceFormValues={provisionalPlaceFormValues}
          proposedSuggestions={proposedSuggestions}
          onSearchAgain={onSearchAgain}
          onCancel={handleOnBack}
          onNext={handleOnNext}
          onSelect={onSelectExistingPlace}
        />
      )}
      {(dialogState === DIALOG_STATES.newPlaceForm || dialogState === DIALOG_STATES.submitted) && (
        <NewProvisionalPlaceForm
          title={headerTitle}
          subtitle={subHeadingText}
          overlay={overlay}
          provisionalPlaceFormValues={provisionalPlaceFormValues}
          onSearchAgain={onSearchAgain}
          onBack={handleOnBack}
          onNext={handleOnNext}
          onSubmit={handleOnSubmit}
          error={error}
          isProposed={isProposed}
        />
      )}
      {dialogState === DIALOG_STATES.proposed && (
        <PlaceRequestSubmittedContent
          title={headerTitle}
          overlay={overlay}
          resetFormState={resetFormState}
          onSubmit={handleOnSubmit}
          provisionalPlaceFormValues={provisionalPlaceFormValues}
        />
      )}
    </Suspense>
  )
}

ProvisionalPlaceNEXT.propTypes = {
  /** The originalText of the name of the place as supplied from PlaceSuggest. */
  placeName: PropTypes.string,
  /** An overlay object obtained from `useOverlay()` */
  overlay: PropTypes.shape({
    close: PropTypes.func,
    isOpen: PropTypes.bool,
    handleClick: PropTypes.func,
    transitioning: PropTypes.bool,
  }).isRequired,
  /** An object containing the submitted place name and place ID.  */
  onSubmit: PropTypes.func,
  /**  An event handler called when the process is cancelled */
  onCancel: PropTypes.func,
  /**  An event handler called whenever an existing place option is selected */
  onSelectExistingPlace: PropTypes.func,
  /** The isProposed flag allows for proposed places to be created. Please, consult the standards team before using. */
  isProposed: PropTypes.bool,
}
